104ã        assert(mul_mod(s1n3, pkn3) == hn3, 'hint mismatch');
105ã        assert(mul_mod(s1n4, pkn4) == hn4, 'hint mismatch');
106ã        assert(mul_mod(s1n5, pkn5) == hn5, 'hint mismatch');
107ã        assert(mul_mod(s1n6, pkn6) == hn6, 'hint mismatch');
108ã        assert(mul_mod(s1n7, pkn7) == hn7, 'hint mismatch');
