190ã    match n {
191ã        0 => 0_u128,
192ã        1 => {
193ã            let a: Zq = v(vals, 0);
194ã            upcast(a)
195ã        },
196ã        2 => {
197ã            let a1: Acc1 = add(v(vals, 0), mul(Q_CONST, v(vals, 1)));
198ã            upcast(a1)
199ã        },
200ã        3 => {
201ã            let a1: Acc1 = add(v(vals, 1), mul(Q_CONST, v(vals, 2)));
202ã            let a2: Acc2 = add(v(vals, 0), mul(Q_CONST, a1));
203ã            upcast(a2)
204ã        },
205ã        4 => {
206ã            let a1: Acc1 = add(v(vals, 2), mul(Q_CONST, v(vals, 3)));
207ã            let a2: Acc2 = add(v(vals, 1), mul(Q_CONST, a1));
208ã            let a3: Acc3 = add(v(vals, 0), mul(Q_CONST, a2));
209ã            upcast(a3)
