351ã/// Pack 512 Zq values into 29 felt252 slots.
352ã/// Each slot encodes up to 18 values: pack_9(lo) + pack_9(hi) * 2^128.
353ãpub fn pack_public_key(values: Span<Zq>) -> Array<felt252> {
354ã    assert!(values.len() == 512, "expected 512 values");
355ã    let mut result: Array<felt252> = array![];
356ã    let mut offset: usize = 0;
357ã    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
358ã    while offset != 504 {
359ã        let lo_felt: felt252 = pack_9(values.slice(offset, 9)).into();
360ã        let hi_felt: felt252 = pack_9(values.slice(offset + 9, 9)).into();
361ã        result.append(lo_felt + hi_felt * TWO_POW_128);
362ã        offset += 18;
363ã    }
364ã    // Last slot: 8 remaining values in low half only
365ã    result.append(pack_9(values.slice(504, 8)).into());
366ã    result
367ã}
