369ã/// Unpack 29 felt252 slots back to 512 Zq values.
370ãpub fn unpack_public_key(packed: Span<felt252>) -> Array<Zq> {
371ã    let mut output: Array<Zq> = array![];
372ã    let mut packed = packed;
373ã    // 28 full slots: 9 lo + 9 hi = 18 values each (504 total)
374ã    let mut i: usize = 0;
375ã    while i != 28 {
376ã        let val_u256: u256 = (*packed.pop_front().unwrap()).into();
377ã        unpack_9_full(val_u256.low, ref output);
378ã        unpack_9_full(val_u256.high, ref output);
379ã        i += 1;
380ã    }
381ã    // Last slot: 8 remaining values in low half
382ã    let val_u256: u256 = (*packed.pop_front().unwrap()).into();
383ã    unpack_8(val_u256.low, ref output);
384ã    output
385ã}
