24ãtype ExtractLQ4 = BoundedInt<0, 14920152705251284194656>;
25ãtype ExtractLQ5 = BoundedInt<0, 1214106331292317047>;
26ãtype ExtractLQ6 = BoundedInt<0, 98796186125178>; // discarded (~47 bits)
27ã
