29ã    type DivT = ExtractLQ1;
30ã    type RemT = Zq;
31ã}
32ã
33ãimpl DivRemLQ1ByQ of DivRemHelper<ExtractLQ1, QConst> {
34ã    type DivT = ExtractLQ2;
35ã    type RemT = Zq;
36ã}
37ã
38ãimpl DivRemLQ2ByQ of DivRemHelper<ExtractLQ2, QConst> {
39ã    type DivT = ExtractLQ3;
40ã    type RemT = Zq;
41ã}
