 15ã
 16ãexport const GET = effectHandler(
 17ã  Effect.gen(function* () {
 18ã    const params = yield* RouteParams;
 19ã    const user = yield* fetchUser(params.id);
 20ã    return Response.json(user);
 21ã  }),
 22ã  AppLayer
