102ãconst data = useEffectOnce(effect, runtime);
103ã
104ã// Run Effect in background (fire-and-forget)
105ãuseForkEffect(effect, runtime, [deps]);
106ã
107ã// Subscribe to Stream
108ãconst values = useStream(stream, runtime);
109ãconst latest = useStreamLatest(stream, runtime, initialValue);
110ã
111ã// Subscribe to SubscriptionRef
112ãconst value = useSubscriptionRef(ref, runtime);
113ã```
