129ã    return yield* db.query("SELECT * FROM users");
130ã  }),
131ã  runtime
132ã);
133ã
134ã// Cache a function with arguments
135ãexport const getUserById = reactCacheFn((id: string) =>
136ã  Effect.gen(function* () {
137ã    const db = yield* Database;
138ã    return yield* db.query(`SELECT * FROM users WHERE id = ${id}`);
139ã  }),
140ã  runtime
141ã);
142ã
143ã// Cache with custom key
144ãexport const getUser = reactCacheWithKey(
145ã  (opts) => fetchUserEffect(opts),
146ã  (opts) => `user:${opts.id}`,
147ã  runtime
