151ã## Headers & Cookies
152ã
153ã```typescript
154ãimport { Headers, Cookies } from "@prb/effect-next/headers";
155ã
156ãEffect.gen(function* () {
157ã  const headers = yield* Headers;
158ã  const userAgent = headers.get("user-agent");
159ã
160ã  const cookies = yield* Cookies;
