165ã## Params
166ã
167ã```typescript
168ãimport { RouteParams, SearchParams } from "@prb/effect-next/params";
169ã
170ãEffect.gen(function* () {
171ã  const params = yield* RouteParams;
172ã  const userId = params.id;
173ã
174ã  const searchParams = yield* SearchParams;
175ã  const page = searchParams.page;
176ã});
177ã```
178ã
179ã## Navigation
180ã
181ã```typescript
182ãimport { redirect, rewrite, notFound } from "@prb/effect-next/navigation";
183ã
184ãEffect.gen(function* () {
185ã  yield* redirect("/login");
186ã  yield* rewrite("/new-path");
187ã  yield* notFound();
188ã});
189ã```
190ã
191ã## Testing Kit
192ã
193ã```typescript
194ãimport {
195ã  assertRight,
196ã  assertLeft,
197ã  expectTaggedFailure,
198ã  expectDefect,
199ã  runExpectSuccess,
200ã  runExpectFailure,
201ã  makeMockRuntime
202ã} from "@prb/effect-next/testing-kit";
203ã
204ã// Assert success
205ãtest("should succeed", async () => {
206ã  const exit = await Effect.runPromiseExit(effect);
207ã  const value = assertRight(exit);
208ã  expect(value).toBe(42);
209ã});
210ã
211ã// Assert specific failure tag
212ãtest("should fail with NotFound", async () => {
213ã  const exit = await Effect.runPromiseExit(effect);
214ã  expectTaggedFailure(exit, "NotFound");
215ã});
216ã
217ã// Run and expect success
218ãtest("should create user", async () => {
219ã  const user = await runExpectSuccess(createUser(), runtime);
220ã  expect(user.name).toBe("Alice");
221ã});
222ã```
223ã
224ã## Best Practices
225ã
226ã1. **Use `Effect.fn()`** ã Automatic telemetry spans and better stack traces
227ã2. **Centralize layers** ã Create `AppLayer` with all shared services
228ã3. **Error handling** ã Use `.catchAll()` or `.catchTag()` for Effect-level errors
229ã4. **Request caching** ã Use `reactCache` for request-scoped memoization
230ã5. **Server-only Effect** ã Effect-ts shines server-side; avoid complex Effect in client components
231ã

