195ã/// Falcon-512 signature scheme parameterized by hash function.
196ã///
197ã/// The `Falcon` struct provides the core cryptographic operations:
198ã/// key generation, signing, and verification.
199ã///
200ã/// # Type Parameter
201ã///
202ã/// - `H`: The hash function used to map messages to polynomials.
203ã///   Use [`Shake256Hash`](crate::hash_to_point::Shake256Hash) for standard
204ã///   Falcon or [`PoseidonHashToPoint`](crate::poseidon_hash::PoseidonHashToPoint) for
205ã///   Starknet compatibility.
206ã///
207ã/// # Example
208ã///
209ã/// ```rust,ignore
210ã/// use falcon_rs::falcon::Falcon;
211ã/// use falcon_rs::hash_to_point::Shake256Hash;
212ã///
213ã/// let (sk, vk) = Falcon::<Shake256Hash>::keygen();
214ã/// let sig = Falcon::<Shake256Hash>::sign(&sk, b"message");
215ã/// assert!(Falcon::<Shake256Hash>::verify(&vk, b"message", &sig).unwrap());
216ã/// ```
217ãpub struct Falcon<H: HashToPoint> {
218ã    _marker: PhantomData<H>,
219ã}
220ã
221ãimpl<H: HashToPoint> Falcon<H> {
222ã    /// Generate a new keypair using system randomness.
223ã    ///
224ã    /// Creates a fresh Falcon-512 keypair using the system's cryptographically
225ã    /// secure random number generator.
226ã    ///
227ã    /// # Returns
228ã    ///
229ã    /// A tuple of (secret key, verifying key).
230ã    ///
231ã    /// # Panics
232ã    ///
233ã    /// Panics if the system RNG fails to provide random bytes.
234ã    #[cfg(feature = "shake")]
235ã    pub fn keygen() -> (SecretKey, VerifyingKey) {
236ã        use getrandom::getrandom;
237ã        let mut seed = [0u8; 32];
238ã        getrandom(&mut seed).expect("Failed to get random bytes");
239ã        Self::keygen_with_seed(&seed)
240ã    }
241ã
242ã    /// Generate a new keypair with a provided seed.
243ã    ///
244ã    /// Creates a deterministic Falcon-512 keypair from the given seed.
245ã    /// The same seed will always produce the same keypair, which is
246ã    /// useful for testing and key recovery.
247ã    ///
248ã    /// # Arguments
249ã    ///
250ã    /// * `seed` - A seed slice (up to 56 bytes used; shorter seeds are zero-padded)
251ã    ///
252ã    /// # Returns
253ã    ///
254ã    /// A tuple of (secret key, verifying key).
255ã    pub fn keygen_with_seed(seed: &[u8]) -> (SecretKey, VerifyingKey) {
256ã        // Create a deterministic RNG from the seed
257ã        let mut full_seed = [0u8; SEED_LEN];
258ã        let copy_len = seed.len().min(SEED_LEN);
259ã        full_seed[..copy_len].copy_from_slice(&seed[..copy_len]);
260ã        let mut rng = ChaCha20::new(&full_seed);
261ã        let mut random_bytes = |n: usize| rng.random_bytes(n);
262ã
263ã        Self::keygen_with_rng(&mut random_bytes)
264ã    }
265ã
266ã    /// Generate a new keypair with a provided random byte source.
267ã    ///
268ã    /// Creates a Falcon-512 keypair using a custom source of randomness.
269ã    /// This is the most flexible key generation method, useful for
270ã    /// deterministic testing or custom RNG implementations.
271ã    ///
272ã    /// # Arguments
273ã    ///
274ã    /// * `random_bytes` - A closure that returns `n` random bytes when called
275ã    ///
276ã    /// # Returns
277ã    ///
278ã    /// A tuple of (secret key, verifying key).
279ã    pub fn keygen_with_rng<F: FnMut(usize) -> Vec<u8>>(
280ã        random_bytes: &mut F,
281ã    ) -> (SecretKey, VerifyingKey) {
282ã        // Generate NTRU polynomials
283ã        let (f, g, capital_f, capital_g) = ntru_gen(random_bytes);
284ã
285ã        // Compute public key h = g/f mod (x^n + 1, q)
286ã        let f_vec: Vec<i32> = f.iter().copied().collect();
287ã        let g_vec: Vec<i32> = g.iter().copied().collect();
288ã        let h_vec = div_zq(&g_vec, &f_vec).expect("f should be invertible");
289ã        let mut h = [0i32; N];
290ã        h.copy_from_slice(&h_vec);
291ã
292ã        // Compute basis B0 = [[g, -f], [G, -F]] in coefficient representation
293ã        // Note: Use regular negation, NOT modular negation (neg_zq), for the Gram matrix
294ã        let neg_f: Vec<f64> = f_vec.iter().map(|&x| -(x as f64)).collect();
295ã        let neg_f_cap: Vec<f64> = capital_f.iter().map(|&x| -(x as f64)).collect();
296ã
297ã        // B0 in coefficient representation (f64 for Gram computation)
298ã        let b0: [[Vec<f64>; 2]; 2] = [
299ã            [g_vec.iter().map(|&x| x as f64).collect(), neg_f],
300ã            [capital_g.iter().map(|&x| x as f64).collect(), neg_f_cap],
301ã        ];
302ã
303ã        // Convert B0 to FFT representation (for use in signing)
304ã        let b0_fft = [
305ã            [fft(&b0[0][0]), fft(&b0[0][1])],
306ã            [fft(&b0[1][0]), fft(&b0[1][1])],
307ã        ];
308ã
309ã        // Compute Gram matrix G0 = B0 * B0^* in coefficient representation
310ã        // (matching Python's approach: gram() in coef domain, then FFT)
311ã        let g0 = gram(&b0);
312ã        let g0_fft = [
313ã            [fft(&g0[0][0]), fft(&g0[0][1])],
314ã            [fft(&g0[1][0]), fft(&g0[1][1])],
315ã        ];
316ã
317ã        // Build ffLDL tree
318ã        let mut tree = ffldl_fft(&g0_fft);
319ã        normalize_tree(&mut tree, SIGMA);
320ã
321ã        let sk = SecretKey {
322ã            f,
323ã            g,
324ã            capital_f,
