  1ã//! Hash-to-point trait for customizable hash functions.
  2ã//!
  3ã//! Falcon requires hashing messages to points in Z_q[X]/(X^n + 1).
  4ã//! This module provides the trait and a default SHAKE256 implementation.
  5ã
  6ãuse crate::{N, Q};
  7ã
  8ã/// Trait for hashing message to polynomial in Z_q[x]/(x^n + 1).
  9ã///
 10ã/// This trait allows swapping the hash function used in Falcon,
 11ã/// enabling use of Poseidon for Starknet compatibility.
 12ã///
 13ã/// The associated type `Input` determines the element type for message and salt:
 14ã/// - `u8` for byte-oriented hashing (SHAKE256)
 15ã/// - `Felt` for field-element hashing (Poseidon/Starknet)
 16ãpub trait HashToPoint {
 17ã    /// Element type for message and salt slices.
 18ã    type Input;
 19ã
 20ã    /// Hash a message with salt to a polynomial in Z_q[x].
 21ã    fn hash_to_point(message: &[Self::Input], salt: &[Self::Input]) -> [i16; N];
 22ã}
 23ã
 24ã/// SHAKE256-based hash (matches Python reference implementation).
 25ã#[cfg(feature = "shake")]
 26ãpub struct Shake256Hash;
 27ã
 28ã#[cfg(feature = "shake")]
 29ãimpl HashToPoint for Shake256Hash {
 30ã    type Input = u8;
 31ã
 32ã    fn hash_to_point(message: &[u8], salt: &[u8]) -> [i16; N] {
 33ã        use sha3::{
 34ã            digest::{ExtendableOutput, Update, XofReader},
 35ã            Shake256,
 36ã        };
 37ã
 38ã        let mut hasher = Shake256::default();
 39ã        hasher.update(salt);
 40ã        hasher.update(message);
 41ã        let mut reader = hasher.finalize_xof();
 42ã
 43ã        // Rejection sampling parameter: k = floor(2^16 / q)
 44ã        let k = (1u32 << 16) / (Q as u32);
 45ã        let mut hashed = [0i16; N];
 46ã        let mut i = 0;
 47ã
 48ã        while i < N {
 49ã            let mut buf = [0u8; 2];
 50ã            reader.read(&mut buf);
 51ã            // Big-endian as per Python reference
 52ã            let elt = ((buf[0] as u32) << 8) | (buf[1] as u32);
 53ã
 54ã            // Rejection sampling to ensure uniform distribution
 55ã            if elt < k * (Q as u32) {
 56ã                hashed[i] = (elt % (Q as u32)) as i16;
 57ã                i += 1;
 58ã            }
 59ã        }
 60ã
 61ã        hashed
 62ã    }
 63ã}
