  1ã//! Poseidon hash_to_point for Falcon-512 (Starknet-compatible).
  2ã//!
  3ã//! Uses lambdaworks PoseidonCairoStark252 to match the Cairo implementation.
  4ã//! Produces 512 coefficients in [0, Q) from (message, salt) using:
  5ã//! - poseidon_hash_span(message || salt) -> single felt252 seed
  6ã//! - Squeeze: 22 hades_permutations, base-Q extraction (12 Zq per felt252)
  7ã
  8ãuse crate::hash_to_point::HashToPoint;
  9ãuse crate::{N, Q};
 10ãuse lambdaworks_crypto::hash::poseidon::starknet::PoseidonCairoStark252;
 11ãuse lambdaworks_crypto::hash::poseidon::Poseidon;
 12ãuse lambdaworks_math::field::element::FieldElement;
 13ãuse lambdaworks_math::field::fields::fft_friendly::stark_252_prime_field::Stark252PrimeField;
 14ã
 15ãpub type Felt = FieldElement<Stark252PrimeField>;
 16ã
 17ãpub struct PoseidonHashToPoint;
 18ã
 19ãimpl HashToPoint for PoseidonHashToPoint {
 20ã    type Input = Felt;
 21ã
 22ã    /// Hash message and salt (as felt252 arrays) to 512 Zq coefficients.
 23ã    /// This matches the Cairo PoseidonHashToPoint implementation exactly.
 24ã    fn hash_to_point(message: &[Felt], salt: &[Felt]) -> [i16; N] {
 25ã        // Absorb: poseidon_hash_span(message || salt) -> single felt252 seed
 26ã        let combined: Vec<Felt> = message.iter().chain(salt.iter()).cloned().collect();
 27ã        let seed = PoseidonCairoStark252::hash_many(&combined);
 28ã
 29ã        // Squeeze: 21 full rounds (504 coefficients) + 1 partial round (8 coefficients)
 30ã        let mut state = [seed, Felt::zero(), Felt::zero()];
 31ã        let mut coeffs = [0i16; N];
 32ã        let mut idx = 0;
 33ã
 34ã        for _ in 0..21 {
 35ã            PoseidonCairoStark252::hades_permutation(&mut state);
 36ã            idx += extract_12_from_felt(&state[0], &mut coeffs, idx);
 37ã            idx += extract_12_from_felt(&state[1], &mut coeffs, idx);
 38ã        }
 39ã
 40ã        // Final round: only need 8 more from state[0]
 41ã        PoseidonCairoStark252::hades_permutation(&mut state);
 42ã        extract_12_from_felt(&state[0], &mut coeffs, idx);
 43ã        // extract_12 stops at N=512, giving exactly 8 (6 from low + 2 from high)
 44ã
 45ã        coeffs
 46ã    }
 47ã}
 48ã
 49ãfn extract_12_from_felt(value: &Felt, out: &mut [i16; N], start: usize) -> usize {
 50ã    let bytes = value.to_bytes_be();
 51ã    // bytes is 32 bytes big-endian: [0..16] = high u128, [16..32] = low u128
 52ã    let high = u128::from_be_bytes(bytes[0..16].try_into().unwrap());
 53ã    let low = u128::from_be_bytes(bytes[16..32].try_into().unwrap());
 54ã
 55ã    let mut count = 0;
 56ã    // Extract 6 from low u128 first (matching Cairo's extract_6_from_low)
 57ã    count += extract_6_from_u128(low, out, start + count);
 58ã    // Extract 6 from high (matching Cairo's extract_6_from_high)
 59ã    count += extract_6_from_u128(high, out, start + count);
 60ã    count
 61ã}
 62ã
 63ãfn extract_6_from_u128(mut value: u128, out: &mut [i16; N], start: usize) -> usize {
 64ã    for i in 0..6 {
 65ã        if start + i >= N {
 66ã            return i;
 67ã        }
 68ã        out[start + i] = (value % Q as u128) as i16;
 69ã        value /= Q as u128;
 70ã    }
 71ã    6
 72ã}
 73ã
