 80ã        let msg = [Felt::from(42u64)];
 81ã        let salt = [Felt::from(1u64), Felt::from(2u64)];
 82ã        let r1 = PoseidonHashToPoint::hash_to_point(&msg, &salt);
 83ã        let r2 = PoseidonHashToPoint::hash_to_point(&msg, &salt);
