101ã        let salt = [Felt::from(0u64), Felt::from(0u64)];
102ã        let r1 = PoseidonHashToPoint::hash_to_point(&msg1, &salt);
103ã        let r2 = PoseidonHashToPoint::hash_to_point(&msg2, &salt);
104ã        assert_ne!(r1, r2);
105ã    }
