  1ã//! Base-Q polynomial packing for Falcon public keys.
  2ã//!
  3ã//! Packs 512 Zq values into 29 felt252 slots using base Q=12289 encoding:
  4ã//!   felt252 = horner_pack(v0..v8) + horner_pack(v9..v17) * 2^128
  5ã//!
  6ã//! Matches the Cairo packing.cairo implementation exactly.
  7ã
  8ãuse crate::poseidon_hash::Felt;
  9ãuse crate::Q;
 10ãuse lambdaworks_math::unsigned_integer::element::UnsignedInteger;
 11ã
 12ãconst VALS_PER_U128: usize = 9;
 13ãconst VALS_PER_FELT: usize = 18;
 14ãpub const PACKED_SLOTS: usize = 29;
 15ã
 16ã/// Convert a u128 to Felt
 17ãfn felt_from_u128(v: u128) -> Felt {
 18ã    Felt::from(&UnsignedInteger::from_u128(v))
 19ã}
 20ã
 21ã/// 2^128 as Felt
 22ãfn two_pow_128() -> Felt {
 23ã    Felt::from_hex("0x100000000000000000000000000000000").unwrap()
 24ã}
 25ã
 26ã/// Pack 512 Zq values into 29 Felt values using base-Q Horner encoding.
 27ãpub fn pack_public_key(h_ntt: &[u16]) -> Vec<Felt> {
 28ã    assert_eq!(h_ntt.len(), 512);
 29ã    h_ntt
 30ã        .chunks(VALS_PER_FELT)
 31ã        .map(|chunk| {
 32ã            let split = chunk.len().min(VALS_PER_U128);
 33ã            let lo = horner_pack(&chunk[..split]);
 34ã            let hi = if chunk.len() > split {
 35ã                horner_pack(&chunk[split..])
 36ã            } else {
 37ã                0u128
 38ã            };
 39ã            felt_from_u128(lo) + felt_from_u128(hi) * two_pow_128()
 40ã        })
 41ã        .collect()
 42ã}
 43ã
 44ã/// Unpack 29 Felt values back to 512 Zq values.
 45ãpub fn unpack_public_key(packed: &[Felt]) -> Vec<u16> {
 46ã    let mut result = Vec::with_capacity(512);
 47ã    let mut remaining = 512usize;
 48ã
 49ã    for felt in packed {
 50ã        let bytes = felt.to_bytes_be();
 51ã        let high = u128::from_be_bytes(bytes[0..16].try_into().unwrap());
 52ã        let low = u128::from_be_bytes(bytes[16..32].try_into().unwrap());
 53ã
 54ã        let lo_count = remaining.min(VALS_PER_U128);
 55ã        base_q_extract(low, lo_count, &mut result);
 56ã        remaining -= lo_count;
 57ã
 58ã        if remaining > 0 {
 59ã            let hi_count = remaining.min(VALS_PER_U128);
 60ã            base_q_extract(high, hi_count, &mut result);
 61ã            remaining -= hi_count;
 62ã        }
 63ã    }
 64ã    result
 65ã}
 66ã
 67ãfn horner_pack(values: &[u16]) -> u128 {
 68ã    let mut acc: u128 = 0;
 69ã    for &v in values.iter().rev() {
 70ã        acc = acc * Q as u128 + v as u128;
 71ã    }
 72ã    acc
 73ã}
 74ã
 75ãfn base_q_extract(mut value: u128, count: usize, out: &mut Vec<u16>) {
 76ã    for _ in 0..count {
 77ã        out.push((value % Q as u128) as u16);
 78ã        value /= Q as u128;
 79ã    }
 80ã}
 81ã
 82ã#[cfg(test)]
 83ãmod tests {
 84ã    use super::*;
 85ã
 86ã    #[test]
 87ã    fn test_packing_roundtrip() {
 88ã        let mut values = vec![0u16; 512];
 89ã        for i in 0..512 {
 90ã            values[i] = (i * 37 % 12289) as u16;
 91ã        }
 92ã        let packed = pack_public_key(&values);
 93ã        assert_eq!(packed.len(), PACKED_SLOTS);
 94ã        let unpacked = unpack_public_key(&packed);
 95ã        assert_eq!(unpacked, values);
 96ã    }
 97ã
 98ã    #[test]
 99ã    fn test_packing_edge_cases() {
100ã        // All zeros
101ã        let zeros = vec![0u16; 512];
102ã        assert_eq!(unpack_public_key(&pack_public_key(&zeros)), zeros);
103ã
104ã        // All max
105ã        let maxes = vec![12288u16; 512];
106ã        assert_eq!(unpack_public_key(&pack_public_key(&maxes)), maxes);
107ã    }
108ã}
