  1ã//! Number Theoretic Transform over Z_q[x]/(x^n + 1).
  2ã
  3ãuse crate::constants::{ntt_roots, I2, INV_MOD_Q, SQR1};
  4ãuse crate::Q;
  5ã
  6ã/// Split a polynomial in NTT representation.
  7ãpub fn split_ntt(f_ntt: &[i32]) -> (Vec<i32>, Vec<i32>) {
  8ã    let n = f_ntt.len();
  9ã    let w = ntt_roots(n);
 10ã    let mut f0_ntt = vec![0i32; n / 2];
 11ã    let mut f1_ntt = vec![0i32; n / 2];
 12ã
 13ã    for i in 0..n / 2 {
 14ã        let sum = (f_ntt[2 * i] + f_ntt[2 * i + 1]).rem_euclid(Q);
 15ã        let diff = (f_ntt[2 * i] - f_ntt[2 * i + 1]).rem_euclid(Q);
 16ã        f0_ntt[i] = ((I2 as i64 * sum as i64) % Q as i64) as i32;
 17ã        f1_ntt[i] =
 18ã            ((I2 as i64 * diff as i64 * INV_MOD_Q[w[2 * i] as usize] as i64) % Q as i64) as i32;
 19ã    }
 20ã    (f0_ntt, f1_ntt)
 21ã}
 22ã
 23ã/// Merge two polynomials in NTT representation.
 24ãpub fn merge_ntt(f0_ntt: &[i32], f1_ntt: &[i32]) -> Vec<i32> {
 25ã    let n = 2 * f0_ntt.len();
 26ã    let w = ntt_roots(n);
 27ã    let mut f_ntt = vec![0i32; n];
 28ã
 29ã    for i in 0..n / 2 {
 30ã        let wf1 = ((w[2 * i] as i64 * f1_ntt[i] as i64) % Q as i64) as i32;
 31ã        f_ntt[2 * i] = (f0_ntt[i] + wf1).rem_euclid(Q);
 32ã        f_ntt[2 * i + 1] = (f0_ntt[i] - wf1).rem_euclid(Q);
 33ã    }
 34ã    f_ntt
 35ã}
 36ã
 37ã/// Compute NTT of a polynomial (coefficient -> NTT representation).
 38ãpub fn ntt(f: &[i32]) -> Vec<i32> {
 39ã    let n = f.len();
 40ã    if n > 2 {
 41ã        let mut f0 = vec![0i32; n / 2];
 42ã        let mut f1 = vec![0i32; n / 2];
 43ã        for i in 0..n / 2 {
 44ã            f0[i] = f[2 * i];
 45ã            f1[i] = f[2 * i + 1];
 46ã        }
 47ã        let f0_ntt = ntt(&f0);
 48ã        let f1_ntt = ntt(&f1);
 49ã        merge_ntt(&f0_ntt, &f1_ntt)
 50ã    } else {
 51ã        let mut f_ntt = vec![0i32; n];
 52ã        f_ntt[0] = (f[0] + ((SQR1 as i64 * f[1] as i64) % Q as i64) as i32).rem_euclid(Q);
 53ã        f_ntt[1] = (f[0] - ((SQR1 as i64 * f[1] as i64) % Q as i64) as i32).rem_euclid(Q);
 54ã        f_ntt
 55ã    }
 56ã}
 57ã
 58ã/// Compute inverse NTT (NTT -> coefficient representation).
 59ãpub fn intt(f_ntt: &[i32]) -> Vec<i32> {
 60ã    let n = f_ntt.len();
 61ã    if n > 2 {
 62ã        let (f0_ntt, f1_ntt) = split_ntt(f_ntt);
 63ã        let f0 = intt(&f0_ntt);
 64ã        let f1 = intt(&f1_ntt);
 65ã        // merge
 66ã        let mut f = vec![0i32; n];
 67ã        for i in 0..n / 2 {
 68ã            f[2 * i] = f0[i];
 69ã            f[2 * i + 1] = f1[i];
 70ã        }
 71ã        f
 72ã    } else {
 73ã        let mut f = vec![0i32; n];
 74ã        let sum = (f_ntt[0] + f_ntt[1]).rem_euclid(Q);
 75ã        let diff = (f_ntt[0] - f_ntt[1]).rem_euclid(Q);
 76ã        f[0] = ((I2 as i64 * sum as i64) % Q as i64) as i32;
 77ã        f[1] = ((I2 as i64 * INV_MOD_Q[SQR1 as usize] as i64 * diff as i64) % Q as i64) as i32;
 78ã        f
 79ã    }
 80ã}
 81ã
 82ã/// Addition of two polynomials in Z_q.
 83ãpub fn add_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
 84ã    assert_eq!(f.len(), g.len());
 85ã    f.iter()
 86ã        .zip(g.iter())
 87ã        .map(|(&a, &b)| (a + b).rem_euclid(Q))
 88ã        .collect()
 89ã}
 90ã
 91ã/// Negation of a polynomial in Z_q.
 92ãpub fn neg_zq(f: &[i32]) -> Vec<i32> {
 93ã    f.iter().map(|&a| (-a).rem_euclid(Q)).collect()
 94ã}
 95ã
 96ã/// Subtraction of two polynomials in Z_q.
 97ãpub fn sub_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
 98ã    add_zq(f, &neg_zq(g))
 99ã}
100ã
101ã/// Multiplication in NTT representation (pointwise).
102ãpub fn mul_ntt(f_ntt: &[i32], g_ntt: &[i32]) -> Vec<i32> {
103ã    assert_eq!(f_ntt.len(), g_ntt.len());
104ã    f_ntt
105ã        .iter()
106ã        .zip(g_ntt.iter())
107ã        .map(|(&a, &b)| ((a as i64 * b as i64) % Q as i64) as i32)
108ã        .collect()
109ã}
110ã
111ã/// Division in NTT representation (pointwise).
112ãpub fn div_ntt(f_ntt: &[i32], g_ntt: &[i32]) -> Option<Vec<i32>> {
113ã    assert_eq!(f_ntt.len(), g_ntt.len());
114ã    if g_ntt.iter().any(|&x| x == 0) {
115ã        return None;
116ã    }
117ã    Some(
118ã        f_ntt
119ã            .iter()
120ã            .zip(g_ntt.iter())
121ã            .map(|(&a, &b)| ((a as i64 * INV_MOD_Q[b as usize] as i64) % Q as i64) as i32)
122ã            .collect(),
123ã    )
124ã}
125ã
126ã/// Multiplication of two polynomials in coefficient representation.
127ãpub fn mul_zq(f: &[i32], g: &[i32]) -> Vec<i32> {
128ã    intt(&mul_ntt(&ntt(f), &ntt(g)))
129ã}
130ã
131ã/// Division of two polynomials in coefficient representation.
132ãpub fn div_zq(f: &[i32], g: &[i32]) -> Option<Vec<i32>> {
133ã    div_ntt(&ntt(f), &ntt(g)).map(|r| intt(&r))
134ã}
