 1ã//! Serialization utilities for generating snforge-compatible JSON test data.
 2ã//!
 3ã//! Produces JSON in the format expected by Cairo's `read_json` + `Serde::deserialize`.
 4ã//! Values must be JSON integers (not strings) for snforge to parse correctly.
 5ã
 6ãuse crate::poseidon_hash::Felt;
 7ãuse num_bigint::BigUint;
 8ãuse serde_json::{json, Number, Value};
 9ã
10ã/// Serialize an array of u16 values as Cairo Serde: [length, v0, v1, ...]
11ãfn serde_u16_array(values: &[u16]) -> Vec<Value> {
12ã    let mut out = Vec::with_capacity(values.len() + 1);
13ã    out.push(Value::Number(Number::from(values.len())));
14ã    for &v in values {
15ã        out.push(Value::Number(Number::from(v)));
16ã    }
17ã    out
18ã}
19ã
20ã/// Serialize an array of Felt values as Cairo Serde: [length, f0, f1, ...]
21ã/// Felt values that fit in u64 are serialized as JSON numbers.
22ã/// Larger values are serialized as decimal strings (snforge handles both).
23ãfn serde_felt_array(values: &[Felt]) -> Vec<Value> {
24ã    let mut out = Vec::with_capacity(values.len() + 1);
25ã    out.push(Value::Number(Number::from(values.len())));
26ã    for v in values {
27ã        out.push(felt_to_json_value(v));
28ã    }
29ã    out
30ã}
31ã
32ãfn felt_to_json_value(f: &Felt) -> Value {
33ã    let bytes = f.to_bytes_be();
34ã    let num = BigUint::from_bytes_be(&bytes);
35ã    let decimal = num.to_string();
36ã    // Use arbitrary_precision to emit large numbers as JSON integers (not strings)
37ã    Value::Number(Number::from_string_unchecked(decimal))
38ã}
39ã
40ã/// Generate snforge-compatible JSON for hash_to_point test data.
41ãpub fn hash_to_point_test_json(
42ã    message: &[Felt],
43ã    salt: &[Felt],
44ã    expected: &[u16],
45ã) -> Value {
46ã    let mut payload = Vec::new();
47ã    payload.extend(serde_felt_array(message));
48ã    payload.extend(serde_felt_array(salt));
49ã    payload.extend(serde_u16_array(expected));
50ã    json!({ "hash_to_point_test": payload })
51ã}
