          <div className="rounded-lg bg-falcon-bg p-3">
            <p className="text-xs font-semibold text-falcon-muted uppercase tracking-wider mb-1">
              Output
            </p>
            <p className="text-sm font-mono text-falcon-text/80">{step.output}</p>
          </div>
        </div>
      )}
    </div>
  )
}
