import { ClaudeCodeAgent, CodexAgent } from "smithers-orchestrator";
import { SuperRalph } from "super-ralph";
import { WORKFLOW_MAX_CONCURRENCY, WORKFLOW_TASK_RETRIES } from "../config";
import { outputs, smithers, Workflow } from "../smithers";
import { focuses } from "./focuses";

const REPO_ROOT = new URL("../../../..", import.meta.url).pathname.replace(
	/\/$/,
	"",
);

// ããã Agent system prompts ããããããããããããããããããããããããããããããããããããããããããããããããããããã

const PLANNING_PROMPT = `You are planning work for the Falcon-512 Demo Website.

MANDATORY: Read these files before planning ANY ticket:
- docs/specs/falcon-demo-website.md (PRD with MoSCoW requirements)
- docs/plans/2026-02-23-falcon-demo-website-design.md (approved architecture)
- docs/plans/2026-02-23-falcon-demo-website-impl.md (12-task implementation plan)
- CLAUDE.md (project conventions)

Architecture rules:
- Next.js 15 App Router at apps/demo/
- Landing sections are React Server Components (zero client JS)
- Interactive sections (verify-playground, pipeline-viz, account-deploy) are client components loaded via next/dynamic with ssr: false
- Effect-TS patterns mandatory: Effect.Service with accessors, Schema.TaggedError for all errors, Effect.fn for all service methods
- State via Effect Atoms (@effect-atom/atom, @effect-atom/atom-react)
- Crypto runs client-side only via falcon-rs WASM (wasm-pack --target web)
- Starknet interactions use starknet.js v9 against mainnet
- Tailwind CSS v4 with CSS-first config (no tailwind.config.js)
- Bun as package manager

Priority ordering:
1. P0 Must Have requirements first (see PRD)
2. Focus dependencies: wasm ã effect-services ã interactive components; landing and styling are independent
3. Never skip tests ã TDD for services, visual verification for components

Security invariants:
- Secret keys never leave the browser (WASM only)
- No server-side crypto operations
- No hardcoded private keys in source
- Validate all starknet.js inputs before RPC calls`;

const IMPLEMENTATION_PROMPT = `You are implementing features for the Falcon-512 Demo Website.

MANDATORY: Read these before implementing:
- docs/specs/falcon-demo-website.md (requirements)
- docs/plans/2026-02-23-falcon-demo-website-impl.md (implementation plan with exact code)
- CLAUDE.md (project conventions)

Mandatory patterns:
- Effect.Service with accessors: true for all services
- Schema.TaggedError for all error types (never throw, never try-catch in Effect.gen)
- Effect.fn("ServiceName.methodName") for all service methods (automatic tracing)
- Effect.try / Effect.tryPromise to wrap fallible operations
- Branded types for IDs (TxHash, ContractAddress)
- Atoms defined OUTSIDE components, use Atom.keepAlive for persistent state
- useAtomValue for reads, useAtomSet for writes in React components
- next/dynamic with ssr: false for all interactive sections
- React Server Components for landing sections (no "use client")

Forbidden patterns:
- try-catch inside Effect.gen (Effect failures are NOT thrown exceptions)
- Type assertions (as any, as never, as unknown)
- console.log (use Effect.log)
- process.env directly (use Config.string)
- Raw promises in services (wrap with Effect.tryPromise)
- Option.getOrThrow (always handle both cases)
- Creating atoms inside React components
- Barrel file imports (import directly from specific modules)

TDD mandate:
- Write failing test first, then implement
- Services: test with Effect.runPromiseExit, assert Exit.isSuccess/isFailure
- Components: verify they render without errors in dev server

Build/typecheck after every change:
  cd apps/demo && bun run typecheck

The falcon-rs crate is at ../../falcon-rs/ (relative to repo root).
WASM build: cd ../../falcon-rs && wasm-pack build --target web --features wasm --out-dir ../s2morrow/apps/demo/public/wasm`;

const TESTING_PROMPT = `You are testing the Falcon-512 Demo Website.

Test runner: bun test (for unit tests in apps/demo/)
Typecheck: cd apps/demo && bun run typecheck
Build: cd apps/demo && bun run build
WASM tests: cd ../../falcon-rs && cargo test

Testing priorities:
1. Effect services ã test each method returns correct Exit type (Success/Failure)
2. Atoms ã test initial values and state transitions
3. Components ã verify rendering in dev server (no component test framework required for P0)
4. WASM bindings ã test via cargo test in falcon-rs, then integration via browser

Patterns:
- Use Effect.runPromiseExit to run effects in tests
- Assert on Exit.isSuccess / Exit.isFailure
- Use Schema.TaggedError _tag for error matching
- Mock WasmRuntime with Layer.succeed for service unit tests
- Test atom state transitions by calling setters and checking values

Coverage requirements:
- Every Effect service method must have at least one success and one failure test
- Every Schema.TaggedError must be constructable and matchable
- WASM: cargo test must pass with all features`;

const REVIEWING_PROMPT = `You are reviewing code for the Falcon-512 Demo Website.

MANDATORY: Read docs/specs/falcon-demo-website.md before reviewing.

Review checklist:
1. Spec compliance ã does implementation match the PRD requirements exactly?
2. Effect patterns ã Effect.Service with accessors, Schema.TaggedError, Effect.fn, no forbidden patterns
3. React patterns ã RSC for landing, client components with next/dynamic, no unnecessary re-renders
4. Type safety ã no type assertions, branded IDs used correctly, proper Option handling
5. Security ã no secret keys in logs/state, no hardcoded credentials
6. Accessibility ã semantic HTML, aria-labels on interactive elements
7. Responsive ã works on mobile (single column) and desktop (grid layouts)
8. Error handling ã every failure path has a specific Schema.TaggedError, user sees meaningful error messages

Severity rules:
- CRITICAL: Security issues, secret key exposure, type assertions, try-catch in Effect.gen
- MAJOR: Missing spec requirements, wrong Effect patterns, accessibility gaps
- MINOR: Style inconsistencies, naming conventions, missing comments`;

const REPORTING_PROMPT = `Write completion reports for the Falcon Demo website.
Be concise. Report what was done, what tests pass, what remains.
Reference PRD requirements by focus area and priority (P0/P1/P2).`;

// ããã Phase skipping ããããããããããããããããããããããããããããããããããããããããããããããããããããããããããã

type Phase = "PROGRESS" | "CODEBASE_REVIEW" | "DISCOVER" | "TICKETS" | "INTEGRATION_TEST";
const PHASES: Phase[] = ["PROGRESS", "CODEBASE_REVIEW", "DISCOVER", "TICKETS", "INTEGRATION_TEST"];
const SKIPTO_PHASE_RAW = process.env.SKIPTO_PHASE?.trim() ?? "";
const SKIPTO_PHASE =
	SKIPTO_PHASE_RAW === ""
		? null
		: PHASES.includes(SKIPTO_PHASE_RAW as Phase)
			? (SKIPTO_PHASE_RAW as Phase)
			: null;

if (SKIPTO_PHASE_RAW !== "" && SKIPTO_PHASE == null) {
	throw new Error(
		`invalid SKIPTO_PHASE: ${SKIPTO_PHASE_RAW}. Expected one of: ${PHASES.join(", ")}`,
	);
}

// ããã Workflow ããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããããã

export default smithers((ctx) => {
	const skipPhases = new Set<string>();
	if (SKIPTO_PHASE && ctx.iteration === 0) {
		const skipIndex = PHASES.indexOf(SKIPTO_PHASE);
		PHASES.forEach((phase, i) => {
			if (i < skipIndex) skipPhases.add(phase);
		});
	}

	return (
		<Workflow name="falcon-demo-factory">
			<SuperRalph
				ctx={ctx}
				outputs={outputs}
				focuses={focuses}
				projectId="falcon-demo"
				projectName="Falcon Demo"
				specsPath="docs/specs/"
				referenceFiles={[
					"docs/specs/falcon-demo-website.md",
					"docs/plans/2026-02-23-falcon-demo-website-design.md",
					"docs/plans/2026-02-23-falcon-demo-website-impl.md",
					"CLAUDE.md",
					"apps/demo/src/",
				]}
				buildCmds={{
					typecheck: "cd apps/demo && bun run typecheck",
					build: "cd apps/demo && bun run build",
				}}
				testCmds={{
					unit: "cd apps/demo && bun test",
					rust: "cd ../../falcon-rs && cargo test",
				}}
				codeStyle={[
					"TypeScript strict mode, no any/never assertions",
					"Effect-TS patterns: Effect.Service with accessors, Schema.TaggedError, Effect.fn for tracing",
					"React: RSC for static content, client components via next/dynamic with ssr: false",
					"Tailwind CSS v4 CSS-first config, custom falcon-* color tokens",
					"Bun as package manager, never npm/yarn",
					"Import directly from modules, never from barrel files",
				].join("\n")}
				reviewChecklist={[
					"Spec compliance ã implementation matches PRD requirements",
					"Effect patterns ã Effect.Service, Schema.TaggedError, Effect.fn, no forbidden patterns",
					"React performance ã RSC where possible, lazy client components, no unnecessary re-renders",
					"Type safety ã branded IDs, proper Option handling, no type assertions",
					"Security ã no secret key exposure, no hardcoded credentials",
					"Accessibility ã semantic HTML, aria-labels on interactive elements",
					"Responsive layout ã single column mobile, grid desktop",
				]}
				maxConcurrency={WORKFLOW_MAX_CONCURRENCY}
				taskRetries={WORKFLOW_TASK_RETRIES}
				skipPhases={skipPhases}
				agents={{
					planning: new ClaudeCodeAgent({
						model: "claude-opus-4-6",
						systemPrompt: PLANNING_PROMPT,
						cwd: REPO_ROOT,
						dangerouslySkipPermissions: true,
						timeoutMs: 30 * 60 * 1000,
					}),
					implementation: new CodexAgent({
						model: "gpt-5.3-codex",
						systemPrompt: IMPLEMENTATION_PROMPT,
						config: {
							model_reasoning_effort: "high",
						},
						cwd: REPO_ROOT,
						yolo: true,
						timeoutMs: 60 * 60 * 1000,
					}),
					testing: new ClaudeCodeAgent({
						model: "claude-sonnet-4-6",
						systemPrompt: TESTING_PROMPT,
						cwd: REPO_ROOT,
						dangerouslySkipPermissions: true,
						timeoutMs: 30 * 60 * 1000,
					}),
					reviewing: new ClaudeCodeAgent({
						model: "claude-opus-4-6",
						systemPrompt: REVIEWING_PROMPT,
						cwd: REPO_ROOT,
						dangerouslySkipPermissions: true,
						timeoutMs: 20 * 60 * 1000,
					}),
					reporting: new ClaudeCodeAgent({
						model: "claude-sonnet-4-6",
						systemPrompt: REPORTING_PROMPT,
						cwd: REPO_ROOT,
						dangerouslySkipPermissions: true,
						timeoutMs: 10 * 60 * 1000,
					}),
				}}
			/>
		</Workflow>
	);
});

